import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

interface Advogado {
  id: number;
  nome: string;
  oab: string;
  email: string;
  telefone: string;
}

const AdvogadosList: React.FC = () => {
  const [advogados, setAdvogados] = useState<Advogado[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [filtro, setFiltro] = useState<string>('');

  useEffect(() => {
    const fetchAdvogados = async () => {
      try {
        setLoading(true);
        const response = await axios.get<Advogado[]>('/api/advogados');
        setAdvogados(response.data);
        setError(null);
      } catch (err) {
        setError('Erro ao carregar advogados. Por favor, tente novamente.');
        console.error('Erro ao buscar advogados:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchAdvogados();
  }, []);

  const handleDelete = async (id: number, nome: string) => {
    if (!window.confirm(`Tem certeza que deseja excluir o advogado "${nome}"?`)) {
      return;
    }

    try {
      await axios.delete(`/api/advogados/${id}`);
      setAdvogados(advogados.filter(advogado => advogado.id !== id));
    } catch (err) {
      setError('Erro ao excluir advogado. Por favor, tente novamente.');
      console.error('Erro ao excluir advogado:', err);
    }
  };

  const advogadosFiltrados = advogados.filter(advogado => {
    const termoBusca = filtro.toLowerCase();
    return (
      advogado.nome.toLowerCase().includes(termoBusca) ||
      advogado.oab.toLowerCase().includes(termoBusca) ||
      (advogado.email && advogado.email.toLowerCase().includes(termoBusca)) ||
      advogado.telefone.toLowerCase().includes(termoBusca)
    );
  });

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-900"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded relative" role="alert">
        <strong className="font-bold">Erro!</strong>
        <span className="block sm:inline"> {error}</span>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-gray-800">Advogados</h1>
        <Link 
          to="/advogados/novo" 
          className="bg-blue-900 hover:bg-blue-800 text-white font-bold py-2 px-4 rounded"
        >
          Novo Advogado
        </Link>
      </div>

      <div className="mb-6">
        <input
          type="text"
          placeholder="Buscar por nome, OAB ou email..."
          className="w-full px-4 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          value={filtro}
          onChange={(e) => setFiltro(e.target.value)}
        />
      </div>

      {advogadosFiltrados.length === 0 ? (
        <div className="bg-gray-50 p-6 rounded-lg text-center">
          <p className="text-gray-600">Nenhum advogado encontrado.</p>
        </div>
      ) : (
        <div className="overflow-x-auto">
          <table className="min-w-full bg-white border border-gray-200 rounded-lg overflow-hidden">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Nome</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Número OAB</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Email</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Telefone</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {advogadosFiltrados.map((advogado) => (
                <tr key={advogado.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{advogado.nome}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{advogado.numeroOAB}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{advogado.email}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{advogado.telefone}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                    <div className="flex space-x-2">
                      <Link to={`/advogados/${advogado.id}`} className="text-blue-600 hover:text-blue-900">
                        Detalhes
                      </Link>
                      <Link to={`/advogados/editar/${advogado.id}`} className="text-indigo-600 hover:text-indigo-900">
                        Editar
                      </Link>
                      <button
                        onClick={() => handleDelete(advogado.id, advogado.nome)}
                        className="text-red-600 hover:text-red-900"
                      >
                        Excluir
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default AdvogadosList;
